import React, { useState, useEffect, useMemo } from "react";
import dayjs from "dayjs";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: { display: false, drawBorder: false },
  ticks: { font: { size: 11 } },
};

function Dashboard() {
  const [users, setUsers] = useState([]);
  const [payments, setPayments] = useState([]);
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(true);

  const currentYear = new Date().getFullYear();
  const [paymentsYear, setPaymentsYear] = useState(currentYear);
  const [leadYear, setLeadYear] = useState(currentYear);
  const [selectedMonth, setSelectedMonth] = useState("all");

  /* ================= FETCH ALL 3 APIs ================= */

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [usersRes, paymentsRes, supportsRes] = await Promise.all([
          axios.get("/api/users"),
          axios.get("/api/payments"),
          axios.get("/api/supports"),
        ]);

        setUsers(usersRes.data.data || []);
        setPayments(paymentsRes.data.data || []);
        setSupports(supportsRes.data.data || []);
      } catch (err) {
        console.error("Dashboard fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  /* ================= SUMMARY CALCULATIONS ================= */

  const totalUsers = users.length;

  const totalClients = users.filter(u => u.isConverted === 1).length;

  const totalRevenue = payments.reduce(
    (sum, p) => sum + Number(p.paidAmount || 0),
    0
  );

  const totalSupportTickets = supports.length;

  /* ================= GROUP USERS (LEADS) ================= */

  const groupedLeads = useMemo(() => {
    return users.reduce((acc, user) => {
      const date = dayjs(user.createdAt);
      const year = date.year();
      const month = date.month() + 1;

      if (!acc[year]) acc[year] = {};
      if (!acc[year][month]) {
        acc[year][month] = {
          leads: 0,
          approved: 0,
          duplicate: 0,
        };
      }

      acc[year][month].leads += 1;

      if (user.status === "approved")
        acc[year][month].approved += 1;

      if (user.status === "duplicate")
        acc[year][month].duplicate += 1;

      return acc;
    }, {});
  }, [users]);

  const leadYearData = groupedLeads[leadYear] || {};
  const leadMonths = Object.keys(leadYearData);

  const leadStatusData = {
    labels: leadMonths.map(m =>
      dayjs(`${leadYear}-${m}-01`).format("MMM")
    ),
    datasets: [
      {
        label: "Total Leads",
        data: leadMonths.map(m => leadYearData[m].leads),
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved",
        data: leadMonths.map(m => leadYearData[m].approved),
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate",
        data: leadMonths.map(m => leadYearData[m].duplicate),
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  /* ================= GROUP PAYMENTS ================= */

  const groupedPayments = useMemo(() => {
    return payments.reduce((acc, payment) => {
      const date = dayjs(payment.paymentDate);
      const year = date.year();
      const month = date.month() + 1;

      if (!acc[year]) acc[year] = {};
      if (!acc[year][month]) {
        acc[year][month] = {
          clients: 0,
          payments: 0,
        };
      }

      acc[year][month].clients += 1;
      acc[year][month].payments += Number(payment.paidAmount || 0);

      return acc;
    }, {});
  }, [payments]);

  const paymentsYearData = groupedPayments[paymentsYear] || {};
  const paymentMonths = Object.keys(paymentsYearData);

  const filteredMonths =
    selectedMonth === "all"
      ? paymentMonths
      : paymentMonths.filter(m => m === selectedMonth);

  const mergedChartData = {
    labels: filteredMonths.map(m =>
      selectedMonth === "all"
        ? dayjs(`${paymentsYear}-${m}-01`).format("MMM YYYY")
        : dayjs(`${paymentsYear}-${m}-01`).format("MMM")
    ),
    datasets: [
      {
        label: "Clients Converted",
        data: filteredMonths.map(
          m => paymentsYearData[m]?.clients || 0
        ),
        backgroundColor: "#0d6efd65",
        yAxisID: "yClients",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: filteredMonths.map(
          m => paymentsYearData[m]?.payments || 0
        ),
        backgroundColor: "#19875475",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
      {
        label: "Commission (10%)",
        data: filteredMonths.map(
          m =>
            Math.round(
              (paymentsYearData[m]?.payments || 0) * 0.1
            )
        ),
        backgroundColor: "#ffc10775",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
    ],
  };

  const mergedChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { ...commonGrid },
      yClients: {
        type: "linear",
        position: "left",
        beginAtZero: true,
        ...commonGrid,
      },
      yAmount: {
        type: "linear",
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
      },
    },
  };

  if (loading)
    return <div className="text-center p-5">Loading Dashboard...</div>;

  return (
    <div className="container py-3">

      {/* SUMMARY */}
      <div className="row g-3">
        <Card title="Total Users" value={totalUsers} />
        <Card title="Total Clients" value={totalClients} />
        <Card
          title="Total Revenue"
          value={`₹${totalRevenue.toLocaleString("en-IN")}`}
        />
        <Card
          title="Support Tickets"
          value={totalSupportTickets}
        />
      </div>

      {/* CHARTS */}
      <div className="row pt-4 g-3">

        <div className="col-lg-6">
          <div className="border rounded p-3 bg-body">
            <h6 className="fw-bold mb-3">
              Leads ({leadYear})
            </h6>
            <Bar data={leadStatusData} />
          </div>
        </div>

        <div className="col-lg-6">
          <div className="border rounded p-3 bg-body">
            <h6 className="fw-bold mb-3">
              Payments ({paymentsYear})
            </h6>
            <Bar
              data={mergedChartData}
              options={mergedChartOptions}
            />
          </div>
        </div>

      </div>
    </div>
  );
}

/* Reusable Card */
const Card = ({ title, value }) => (
  <div className="col-md-3 col-6">
    <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-25">
      <small>{title}</small>
      <h5>{value}</h5>
    </div>
  </div>
);

export default Dashboard;
